import React, { useState, useEffect, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useDataContext } from '../App';
import {
  Box,
  Typography,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Grid,
  Card,
  CardContent,
  CardHeader,
  CardActions,
  LinearProgress,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  Chip,
  Divider,
  Alert,
  IconButton,
  useTheme,
  CircularProgress,
  Paper,
  Container,
  Select,
  MenuItem,
} from '@mui/material';
import {
  BarChart as ChartIcon,
  Add as AddIcon,
  Timeline as TimelineIcon,
  BubbleChart as ScatterIcon,
  ShowChart as LineIcon,
  PieChart as PieIcon,
  Delete as DeleteIcon,
  Edit as EditIcon,
  CheckCircle as CheckCircleIcon,
  ArrowBack as ArrowBackIcon,
  ErrorOutline as ErrorOutlineIcon,
  File as FileIcon,
} from '@mui/icons-material';
import PageHeader from '../components/common/PageHeader';
import { Chart, registerables } from 'chart.js/auto';
import { fetchApi } from '../services/api';

// Register all chart components
Chart.register(...registerables);

function Visualizations() {
  const theme = useTheme();
  const location = useLocation();
  const navigate = useNavigate();
  const { lastUpdate, backendAvailable } = useDataContext();
  const [openDialog, setOpenDialog] = useState(false);
  const [openDeleteDialog, setOpenDeleteDialog] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [selectedFile, setSelectedFile] = useState(null);
  const [files, setFiles] = useState([]);
  const [visualizations, setVisualizations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [analysis, setAnalysis] = useState(null);
  const [error, setError] = useState(null);
  const [openViewDialog, setOpenViewDialog] = useState(false);
  const [currentVisualization, setCurrentVisualization] = useState(null);
  const [openEditDialog, setOpenEditDialog] = useState(false);
  const chartContainerRef = useRef(null);
  const [chartInstance, setChartInstance] = useState(null);
  const [selectedXAxis, setSelectedXAxis] = useState('');
  const [selectedYAxis, setSelectedYAxis] = useState('');
  const [showChartOptions, setShowChartOptions] = useState(false);
  const [previewCharts, setPreviewCharts] = useState([]);
  const [previewFile, setPreviewFile] = useState(null);
  const [axisSelectionOpen, setAxisSelectionOpen] = useState(false);
  const chartPreviewRefs = useRef({});
  const [chartPreviewInstances, setChartPreviewInstances] = useState({});
  const [fileNotFound, setFileNotFound] = useState(false);
  const [loadingTimeout, setLoadingTimeout] = useState(null);

  // Track mounted state for cleanup
  const isMounted = useRef(true);
  
  // Clean up chart instances and timeouts when component unmounts
  useEffect(() => {
    return () => {
      isMounted.current = false;
      
      // Clear loading timeout if exists
      if (loadingTimeout) {
        clearTimeout(loadingTimeout);
      }
      
      // Clean up all chart instances
      Object.values(chartPreviewInstances).forEach(chart => {
        if (chart && typeof chart.destroy === 'function') {
          chart.destroy();
        }
      });
      
      if (chartInstance && typeof chartInstance.destroy === 'function') {
        chartInstance.destroy();
      }
    };
  }, [loadingTimeout, chartPreviewInstances, chartInstance]);

  useEffect(() => {
    if (isMounted.current) {
      // Set a timeout to prevent infinite loading
      const timeout = setTimeout(() => {
        if (loading && isMounted.current) {
          console.log('[Visualizations] Loading timeout triggered, resetting loading state');
          setLoading(false);
        }
      }, 10000); // 10 second timeout
      
      setLoadingTimeout(timeout);
      
      // Load initial data
      fetchFiles();
      fetchVisualizations();
      
      if (location.state?.openCreateDialog) {
        setOpenDialog(true);
        window.history.replaceState({}, document.title);
      }
    }
  }, [location, lastUpdate]);

  const fetchFiles = async (retryCount = 0) => {
    if (!isMounted.current) return;
    
    try {
      setFileNotFound(false);
      setError(null);
      
      console.log('[Visualizations] Fetching files, attempt', retryCount + 1);
      
      // Network status check
      if (navigator.onLine === false) {
        console.error('[Visualizations] Browser is offline');
        setError('Network connection unavailable');
        return;
      }
      
      const response = await fetchApi('/api/files');
      const data = await response.json();
      console.log('[Visualizations] Files fetched:', data);
      
      if (!isMounted.current) return;
      
      if (data.files && Array.isArray(data.files)) {
        setFiles(data.files || []);
        if (data.files.length === 0) {
          console.log('[Visualizations] No files found in response');
          // Clear preview charts when no files exist
          setPreviewCharts([]);
          setPreviewFile(null);
        }
      } else {
        console.warn('[Visualizations] Files data format unexpected:', data);
        setFiles([]);
      }
    } catch (error) {
      if (!isMounted.current) return;
      
